/**
 * Furniture catalog: defines all placeable furniture items.
 * Sprite regions reference furniture-sheet.png (512x1696).
 * Auto-generated by asset-pipeline Stage 5.
 */

export interface SpriteRegion {
  x: number;
  y: number;
  w: number;
  h: number;
}

export interface FurnitureDef {
  id: string;
  label: string;
  category: FurnitureCategory;
  widthCells: number;
  heightCells: number;
  sprite: SpriteRegion;
  /** Override spritesheet path (default: furniture-sheet.png) */
  sheetPath?: string;
  canPlaceOnWalls?: boolean;
  isSeat?: boolean;
  isDesk?: boolean;
  /** 걸어갈 수 있는 footprint 내부 셀 offset (col,row). 지정 시 해당 셀은 grid 점유 안 함.
   *  L자 책상처럼 footprint는 크지만 일부는 실제 투명/빈 공간일 때 사용. */
  walkableCells?: Array<[number, number]>;
}

export type FurnitureCategory = "accessory" | "appliance" | "board" | "chair" | "desk" | "divider" | "floor_decor" | "floor_tile" | "partition" | "plant" | "seating" | "storage" | "wall_decor" | "wall_tile";

/** Categories that characters can walk through/over
 *  (wall_tile 제외 — 벽은 통과 불가) */
export const WALKABLE_CATEGORIES = new Set<FurnitureCategory>([
  "chair", "seating", "floor_tile", "wall_decor", "floor_decor", "accessory",
]);

