const ROOM_BUILDER_TILES: FurnitureDef[] = ROOM_BUILDER_RAW.map(r => ({
  ...r,
  sheetPath: ROOM_BUILDER_SHEET,
  canPlaceOnWalls: true,
}));

const catalogMap = new Map([...FURNITURE_CATALOG, ...ROOM_BUILDER_TILES].map(f => [f.id, f]));

export function getFurnitureDef(id: string): FurnitureDef | undefined {
  return catalogMap.get(id);
}

export function getFurnitureByCategory(category: FurnitureCategory): FurnitureDef[] {
  return Array.from(catalogMap.values()).filter(f => f.category === category);
}

export function getAllFurniture(): FurnitureDef[] {
  return Array.from(catalogMap.values());
}

/** Update label and/or category of a furniture item, persisted to localStorage */
export function updateFurnitureMeta(
  id: string,
  updates: { label?: string; category?: FurnitureCategory },
): void {
  const def = catalogMap.get(id);
  if (!def) return;
  const updated = { ...def, ...updates };
  catalogMap.set(id, updated);
  const idx = FURNITURE_CATALOG.findIndex((f) => f.id === id);
  if (idx >= 0) FURNITURE_CATALOG[idx] = updated;
  _saveOverrides();
  try { syncFurnitureOverridesToServer(); } catch {}
}

// --- Persistence helpers ---
const OVERRIDES_KEY = "teammaker-furniture-overrides";

interface FurnitureOverride {
  label?: string;
  category?: FurnitureCategory;
  deleted?: boolean;
}

// 관리자가 숨긴 아이템 id 집합 (localStorage 기반)
const _hiddenIds = new Set<string>();

export function isHiddenFurniture(id: string): boolean {
  return _hiddenIds.has(id);
}

export function getVisibleFurnitureList(): FurnitureDef[] {
  return Array.from(catalogMap.values()).filter(f => !_hiddenIds.has(f.id));
}

/** 관리자 삭제: 팔레트에서 숨김 처리(복구는 restoreFurniture) */
export function deleteFurniture(id: string): void {
  _hiddenIds.add(id);
  _saveOverrides();
  try { syncFurnitureOverridesToServer(); } catch {}
}

/** 관리자 복구: 삭제된 아이템 다시 노출 */
export function restoreFurniture(id: string): void {
  _hiddenIds.delete(id);
  _saveOverrides();
  try { syncFurnitureOverridesToServer(); } catch {}
}

function _saveOverrides(): void {
  if (typeof window === "undefined") return;
  const overrides: Record<string, FurnitureOverride> = {};
  for (const [id, def] of catalogMap) {
    const orig = _originalMap.get(id);
    if (!orig) continue;
    const o: FurnitureOverride = {};
    if (def.label !== orig.label) o.label = def.label;
    if (def.category !== orig.category) o.category = def.category;
    if (_hiddenIds.has(id)) o.deleted = true;
    if (Object.keys(o).length > 0) overrides[id] = o;
  }
  // 원본에 없는 id 도 숨김 가능성 있음 (향후 확장)
  for (const id of _hiddenIds) {
    if (!overrides[id]) overrides[id] = { deleted: true };
  }
  if (Object.keys(overrides).length > 0) {
    localStorage.setItem(OVERRIDES_KEY, JSON.stringify(overrides));
  } else {
    localStorage.removeItem(OVERRIDES_KEY);
  }
}

function _loadOverrides(): void {
  if (typeof window === "undefined") return;
  try {
    const raw = localStorage.getItem(OVERRIDES_KEY);
    if (!raw) return;
    const overrides: Record<string, FurnitureOverride> = JSON.parse(raw);
    for (const [id, o] of Object.entries(overrides)) {
      if (o.deleted) _hiddenIds.add(id);
      const def = catalogMap.get(id);
      if (!def) continue;
      const { deleted: _d, ...rest } = o;
      const updated = { ...def, ...rest };
      catalogMap.set(id, updated);
      const idx = FURNITURE_CATALOG.findIndex((f) => f.id === id);
      if (idx >= 0) FURNITURE_CATALOG[idx] = updated;
    }
  } catch { /* ignore corrupt data */ }
}

// Keep a snapshot of originals for diffing
const _originalMap = new Map(catalogMap);

// Load overrides on module init
_loadOverrides();

// ── 서버 동기화 (모든 관리자 기기 공유) ─────────────────
function _apiBase(): string {
  if (typeof window === "undefined") return "";
  const h = window.location.hostname;
  const isLocal = h === "localhost" || h === "127.0.0.1" || h.endsWith(".local") || h.startsWith("192.168.");
  return isLocal ? `http://${h}:8000` : "https://api.600g.net";
}

const POKE_LABEL_KEY = "hq-poke-label-overrides";
const POKE_HIDDEN_KEY = "hq-poke-hidden";
const TILE_LABEL_KEY = "hq-tile-label-overrides";
const TILE_HIDDEN_KEY = "hq-tile-hidden";

function _applyServerOverrides(serverOverrides: Record<string, FurnitureOverride>): void {
  if (typeof window === "undefined") return;
  // 1) 카탈로그 정의 업데이트
  for (const [id, o] of Object.entries(serverOverrides)) {
    if (o.deleted) _hiddenIds.add(id); else _hiddenIds.delete(id);
    const def = catalogMap.get(id);
    if (!def) continue;
    const { deleted: _d, ...rest } = o;
    const updated = { ...def, ...rest };
    catalogMap.set(id, updated);
    const idx = FURNITURE_CATALOG.findIndex((f) => f.id === id);
    if (idx >= 0) FURNITURE_CATALOG[idx] = updated;
  }
  // 2) localStorage 미러 (오프라인에서도 즉시 반영되게)
  _saveOverrides();
}

/** 서버에서 오버라이드 받아와 적용. 앱 부팅 시 + 관리자가 편집기 열 때 호출. */
export async function fetchAndApplyFurnitureOverrides(): Promise<void> {
  if (typeof window === "undefined") return;
  try {
    const res = await fetch(`${_apiBase()}/api/furniture/overrides`, { cache: "no-store" });
    if (!res.ok) { console.warn("[hq-furn] fetch failed", res.status); return; }
    const j = await res.json();
    const data = j?.overrides;
    if (!data) return;
    // 포맷: {"version":1, "overrides":{...}, "poke_labels":{...}, "poke_hidden":[...]}
    const overrides = data.overrides || {};
    const count = Object.keys(overrides).length;
    console.info(`[hq-furn] overrides fetched: ${count} items`);
    _applyServerOverrides(overrides);
    // poke
    if (data.poke_labels && typeof data.poke_labels === "object") {
      try { localStorage.setItem(POKE_LABEL_KEY, JSON.stringify(data.poke_labels)); } catch {}
    }
    if (Array.isArray(data.poke_hidden)) {
      try { localStorage.setItem(POKE_HIDDEN_KEY, JSON.stringify(data.poke_hidden)); } catch {}
    }
    // tile
    if (data.tile_labels && typeof data.tile_labels === "object") {
      try { localStorage.setItem(TILE_LABEL_KEY, JSON.stringify(data.tile_labels)); } catch {}
    }
    if (Array.isArray(data.tile_hidden)) {
      try { localStorage.setItem(TILE_HIDDEN_KEY, JSON.stringify(data.tile_hidden)); } catch {}
    }
    if (typeof window !== "undefined") {
      window.dispatchEvent(new CustomEvent("hq:furniture-overrides-applied"));
    }
  } catch { /* ignore */ }
}

let _syncDebounce: ReturnType<typeof setTimeout> | null = null;

/** 현재 오버라이드를 서버에 저장 (디바운스). 관리자만 성공 유효. */
export function syncFurnitureOverridesToServer(): void {
  if (typeof window === "undefined") return;
  if (_syncDebounce) clearTimeout(_syncDebounce);
  _syncDebounce = setTimeout(async () => {
    // 현재 override 상태 수집
    const overrides: Record<string, FurnitureOverride> = {};
    for (const [id, def] of catalogMap) {
      const orig = _originalMap.get(id);
      if (!orig) continue;
      const o: FurnitureOverride = {};
      if (def.label !== orig.label) o.label = def.label;
      if (def.category !== orig.category) o.category = def.category;
      if (_hiddenIds.has(id)) o.deleted = true;
      if (Object.keys(o).length > 0) overrides[id] = o;
    }
    for (const id of _hiddenIds) if (!overrides[id]) overrides[id] = { deleted: true };
    // 포켓몬/타일 (localStorage → 서버)
    const readJson = <T>(key: string, fallback: T): T => {
      try { const raw = localStorage.getItem(key); return raw ? JSON.parse(raw) as T : fallback; }
      catch { return fallback; }
    };
    const pokeLabels = readJson<Record<string, string>>(POKE_LABEL_KEY, {});
    const pokeHidden = readJson<string[]>(POKE_HIDDEN_KEY, []);
    const tileLabels = readJson<Record<string, string>>(TILE_LABEL_KEY, {});
    const tileHidden = readJson<string[]>(TILE_HIDDEN_KEY, []);
    try {
      await fetch(`${_apiBase()}/api/furniture/overrides`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          overrides,
          poke_labels: pokeLabels, poke_hidden: pokeHidden,
          tile_labels: tileLabels, tile_hidden: tileHidden,
        }),
      });
    } catch { /* 오프라인이어도 localStorage는 이미 반영됨 */ }
  }, 600);
}

// 서버 overrides 동기화 (이름 변경/카테고리/숨김) — 이전 ui/ 에서 편집한 내역 복구용
//  · 부팅 시 1회 fetch (기기 간 공유 + localStorage 보강)
//  · 그 후는 필요 시 수동 호출 (polling 비활성화 — 토큰/요청 절약)
if (typeof window !== "undefined") {
  setTimeout(() => {
    fetchAndApplyFurnitureOverrides().catch(() => { /* 서버 없어도 localStorage 로 동작 */ });
  }, 500);
  document.addEventListener("visibilitychange", () => {
    if (document.visibilityState === "visible") {
      fetchAndApplyFurnitureOverrides().catch(() => {});
    }
  });
}

/** Export current overrides as JSON string (for applying to source code) */
export function exportOverrides(): string | null {
  const overrides: Record<string, FurnitureOverride> = {};
  for (const [id, def] of catalogMap) {
    const orig = _originalMap.get(id);
    if (!orig) continue;
    const o: FurnitureOverride = {};
    if (def.label !== orig.label) o.label = def.label;
    if (def.category !== orig.category) o.category = def.category;
    if (Object.keys(o).length > 0) overrides[id] = o;
  }
  if (Object.keys(overrides).length === 0) return null;
  return JSON.stringify(overrides, null, 2);
}

/** Get the count of current overrides */
export function getOverrideCount(): number {
  let count = 0;
  for (const [id, def] of catalogMap) {
    const orig = _originalMap.get(id);
    if (!orig) continue;
    if (def.label !== orig.label || def.category !== orig.category) count++;
  }
  return count;
}
